const { execSync } = require('child_process');

function generatePackageLock() {
  try {
    // Update package-lock.json to ensure all dependencies are locked
    execSync('npm install', { stdio: 'inherit' });
    console.log('package-lock.json generated successfully.');
  } catch (error) {
    console.error('Failed to generate package-lock.json:', error.message);
  }
}

function updateDependencies() {
  try {
    // Update all dependencies to their latest versions without modifying package-lock.json
    execSync('npm-check-updates -u', { stdio: 'inherit' });
    
    // Reinstall to update package-lock.json with the new versions
    execSync('npm install', { stdio: 'inherit' });
    console.log('Dependencies updated and package-lock.json regenerated.');
  } catch (error) {
    console.error('Failed to update dependencies:', error.message);
  }
}

